      out.write("</script>\n");
      out.write("\n");
      out.write("			<script>\n");
      out.write("			function submitPassword() {\n");
      out.write("			    const newPassword = document.getElementById(\"newPassword\").value.trim();\n");
      out.write("			    const confirmPassword = document.getElementById(\"confirmPassword\").value.trim();\n");
      out.write("\n");
      out.write("			    if (!newPassword || !confirmPassword) {\n");
      out.write("			        showToast(\"Please fill all fields\", \"error\");\n");
      out.write("			        return;\n");
      out.write("			    }\n");
      out.write("\n");
      out.write("			    fetch(\"");
      out.print(request.getContextPath());
      out.write("/changePassword\", {\n");
      out.write("			        method: \"POST\",\n");
      out.write("			        headers: {\n");
      out.write("			            \"Content-Type\": \"application/x-www-form-urlencoded\"\n");
      out.write("			        },\n");
      out.write("			        body: new URLSearchParams({\n");
      out.write("			            newPassword: newPassword,\n");
      out.write("			            confirmPassword: confirmPassword\n");
      out.write("			        })\n");
      out.write("			    })\n");
      out.write("			    .then(res => res.text())\n");
      out.write("			    .then(data => {\n");
      out.write("			        if (data === \"Success\") {\n");
      out.write("			            showToast(\"Password updated successfully\", \"success\");\n");
      out.write("			            closeChangePassword();\n");
      out.write("			            document.getElementById(\"newPassword\").value = \"\";\n");
      out.write("			            document.getElementById(\"confirmPassword\").value = \"\";\n");
      out.write("			        }\n");
      out.write("			        else if (data === \"PasswordMismatch\") {\n");
      out.write("			            showToast(\"Passwords do not match\", \"error\");\n");
      out.write("			        }\n");
      out.write("			        else if (data === \"MissingFields\") {\n");
      out.write("			            showToast(\"All fields are required\", \"error\");\n");
      out.write("			        }\n");
      out.write("			        else if (data === \"Unauthorized\") {\n");
      out.write("			            showToast(\"Session expired. Please login again.\", \"error\");\n");
      out.write("			        }\n");
      out.write("			        else {\n");
      out.write("			            showToast(\"Something went wrong\", \"error\");\n");
      out.write("			        }\n");
      out.write("			    })\n");
