      out.write("			<!-- ====== BREAK TIME SCRIPT ====== -->\n");
      out.write("			<script>\n");
      out.write("			let breakStartTime = null;\n");
      out.write("			let breakInterval  = null;\n");
      out.write("			let totalBreakMs   = 0;\n");
      out.write("			let breakEntries   = [];\n");
      out.write("\n");
      out.write("			function fmtTime(ms) {\n");
      out.write("			    const s  = Math.floor(ms / 1000);\n");
      out.write("			    const h  = Math.floor(s / 3600);\n");
      out.write("			    const m  = Math.floor((s % 3600) / 60);\n");
      out.write("			    const sc = s % 60;\n");
      out.write("			    return [h, m, sc].map(x => String(x).padStart(2, '0')).join(':');\n");
      out.write("			}\n");
      out.write("\n");
      out.write("			function startBreak() {\n");
      out.write("			    if (breakStartTime) return;\n");
      out.write("			    breakStartTime = Date.now();\n");
      out.write("			    document.getElementById('startBreakBtn').disabled = true;\n");
      out.write("			    document.getElementById('endBreakBtn').disabled   = false;\n");
      out.write("			    document.getElementById('breakStatusBadge').style.display = 'flex';\n");
      out.write("\n");
      out.write("			    breakInterval = setInterval(() => {\n");
      out.write("			        const elapsed = Date.now() - breakStartTime;\n");
      out.write("			        document.getElementById('breakTimer').textContent = fmtTime(elapsed);\n");
      out.write("			    }, 1000);\n");
      out.write("			}\n");
      out.write("\n");
      out.write("			function endBreak() {\n");
      out.write("			    if (!breakStartTime) return;\n");
      out.write("			    clearInterval(breakInterval);\n");
      out.write("\n");
      out.write("			    const dur   = Date.now() - breakStartTime;\n");
      out.write("			    totalBreakMs += dur;\n");
      out.write("\n");
      out.write("			    const start = new Date(breakStartTime);\n");
      out.write("			    const end   = new Date();\n");
      out.write("			    breakEntries.push({ start, end, dur });\n");
      out.write("\n");
      out.write("			    renderBreakLog();\n");
      out.write("\n");
      out.write("			    breakStartTime = null;\n");
      out.write("			    document.getElementById('startBreakBtn').disabled = false;\n");
      out.write("			    document.getElementById('endBreakBtn').disabled   = true;\n");
      out.write("			    document.getElementById('breakStatusBadge').style.display = 'none';\n");
      out.write("			    document.getElementById('breakTimer').textContent = '00:00:00';\n");
      out.write("			    document.getElementById('totalBreakTime').textContent = fmtTime(totalBreakMs);\n");
      out.write("			}\n");
      out.write("\n");
      out.write("			function renderBreakLog() {\n");
      out.write("			    const log = document.getElementById('breakLog');\n");
      out.write("			    log.innerHTML = '';\n");
      out.write("			    breakEntries.forEach((e, i) => {\n");
      out.write("			        const fmt = t => t.toTimeString().substring(0, 8);\n");
      out.write("			        const div = document.createElement('div');\n");
      out.write("			        div.className = 'break-entry';\n");
      out.write("			        div.innerHTML =\n");
