      out.write("			            '<span class=\"be-dur\">' + fmtTime(e.dur) + '</span>';\n");
      out.write("			        log.appendChild(div);\n");
      out.write("			    });\n");
      out.write("			}\n");
      out.write("			</script>\n");
      out.write("\n");
